def update_account_balance(transactions, initial_balance):
    if not isinstance(transactions, list) or not all(isinstance(t, tuple) for t in transactions):
        raise ValueError("Transactions must be a list of tuples")
    
    if not isinstance(initial_balance, (int, float)):
        raise ValueError("Initial balance must be an integer or float")
    
    current_balance = initial_balance
    
    for transaction in transactions:
        if len(transaction) != 2:
            raise ValueError("Each transaction must have exactly two elements")
        
        action, amount = transaction
        
        if not isinstance(action, str) or action.lower() not in ['deposit', 'withdraw']:
            raise ValueError("Transaction action must be 'deposit' or 'withdraw'")
        
        if not isinstance(amount, (int, float)) or amount < 0:
            raise ValueError("Transaction amount must be a non-negative number")
        
        if action.lower() == 'deposit':
            current_balance += amount
        elif action.lower() == 'withdraw':
            if amount > current_balance:
                raise ValueError("Insufficient funds for withdrawal")
            current_balance -= amount
    
    return current_balance